package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader) {
            // Override read() to delegate to mockReader.read()
            @Override
            public int read() throws IOException {
                return super.read();
            }
        };
    }

    @Test
    void testReadReturnsCharAndUpdatesLastCharWithoutNewline() throws IOException {
        // Setup mock to return 'a' (not newline)
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn((int) 'a').when(spyReader).read();
        // We must call the real super.read() so we spy on super.read()
        // But since super.read() is BufferedReader.read(), we cannot mock it easily.
        // Instead, we create a subclass with a mock Reader and call read().

        // Instead, let's create a subclass that uses a Reader returning 'a'
        Reader reader = new Reader() {
            boolean readOnce = false;
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                return -1;
            }
            @Override
            public int read() throws IOException {
                if (!readOnce) {
                    readOnce = true;
                    return 'a';
                }
                return -1;
            }
            @Override
            public void close() throws IOException {}
        };

        ExtendedBufferedReader readerUnderTest = new ExtendedBufferedReader(reader);
        int result = readerUnderTest.read();
        assertEquals('a', result);
        // Using reflection to get lastChar and lineCounter
        int lastChar = getPrivateField(readerUnderTest, "lastChar");
        int lineCounter = getPrivateField(readerUnderTest, "lineCounter");
        assertEquals('a', lastChar);
        assertEquals(0, lineCounter);
    }

    @Test
    void testReadReturnsNewlineAndIncrementsLineCounter() throws IOException {
        Reader reader = new Reader() {
            boolean readOnce = false;
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                return -1;
            }
            @Override
            public int read() throws IOException {
                if (!readOnce) {
                    readOnce = true;
                    return '\n';
                }
                return -1;
            }
            @Override
            public void close() throws IOException {}
        };

        ExtendedBufferedReader readerUnderTest = new ExtendedBufferedReader(reader);
        int result = readerUnderTest.read();
        assertEquals('\n', result);
        int lastChar = getPrivateField(readerUnderTest, "lastChar");
        int lineCounter = getPrivateField(readerUnderTest, "lineCounter");
        assertEquals('\n', lastChar);
        assertEquals(1, lineCounter);
    }

    @Test
    void testReadReturnsEndOfStream() throws IOException {
        Reader reader = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                return -1;
            }
            @Override
            public int read() throws IOException {
                return -1;
            }
            @Override
            public void close() throws IOException {}
        };

        ExtendedBufferedReader readerUnderTest = new ExtendedBufferedReader(reader);
        int result = readerUnderTest.read();
        assertEquals(-1, result);
        int lastChar = getPrivateField(readerUnderTest, "lastChar");
        int lineCounter = getPrivateField(readerUnderTest, "lineCounter");
        assertEquals(-1, lastChar);
        assertEquals(0, lineCounter);
    }

    @SuppressWarnings("unchecked")
    private int getPrivateField(Object instance, String fieldName) {
        try {
            java.lang.reflect.Field field = instance.getClass().getDeclaredField(fieldName);
            field.setAccessible(true);
            return (int) field.get(instance);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
